#include <stdio.h>
#include <limits.h>

int main() {
    int n, a, b, c;
    scanf("%d %d %d %d", &n, &a, &b, &c);

    int dp[n + 1];
    dp[0] = 0;
    for (int i = 1; i <= n; i++) {
        dp[i] = -INT_MAX;
    }

    for (int i = a; i <= n; i++) {
        if (dp[i - a] + 1 > dp[i]) {
            dp[i] = dp[i - a] + 1;
        }
    }

    for (int i = b; i <= n; i++) {
        if (dp[i - b] + 1 > dp[i]) {
            dp[i] = dp[i - b] + 1;
        }
    }

    for (int i = c; i <= n; i++) {
        if (dp[i - c] + 1 > dp[i]) {
            dp[i] = dp[i - c] + 1;
        }
    }

    printf("%d", dp[n]);
    return 0;
}
